// Parse Claude's JSON reply, fall back gracefully
const raw = $input.first().json.result || '';
const match = raw.match(/\{[\s\S]*\}/);
let parsed = {};
try { parsed = JSON.parse(match ? match[0] : raw); }
catch (e) { parsed = { parse_error: e.message, raw: raw.slice(0, 500) }; }
parsed.url = $('Webhook (paste LinkedIn URL)').first().json.body.url;
parsed.enriched_at = new Date().toISOString();
return { json: parsed };
